ee:message.ee:set-payload:
%dw 2.0 output text/plain var errorDetails = { "Error Type": error.errorType.asString default "UNKNOWN", "Error Description": error.description default "Unknown error", "Detailed Description": error.detailedDescription default "No additional details", "Message": payload.messages default (error.description default "Unknown error"), "Correlation ID": vars.correlationId default "", "Transaction ID": vars.transactionId default "", "Timestamp": now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSS"}, "Environment": p('mule.env') default "unknown", "Application": p('application.name') default "unknown", "Event Type": vars.eventType default "UNKNOWN" }
--- "Error Details: -------------------------------------------------- Error Type: " ++ errorDetails."Error Type" ++ " Error Description: " ++ errorDetails."Error Description" ++ " Detailed Description: " ++ errorDetails."Detailed Description" ++ " Message: " ++ errorDetails.Message ++ " Correlation ID: " ++ errorDetails."Correlation ID" ++ " Transaction ID: " ++ errorDetails."Transaction ID" ++ " Timestamp: " ++ errorDetails.Timestamp ++ " Environment: " ++ errorDetails.Environment ++ " Application: " ++ errorDetails.Application ++ " Event Type: " ++ errorDetails."Event Type" ++ " --------------------------------------------------
This is an automated message. Please do not reply to this email."

%dw 2.0
output application/json
---
{
  "status": "ERROR",
  "message": "An error occurred during integration processing. Support team has been notified.",
  "errorType": error.errorType.identifier default "UNKNOWN",
  "correlationId": vars.correlationId default "",
  "timestamp": now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSS"}
}
